export const nextGeneration = (cells: Cell[]): Cell[] => {
  const isAlive = (cell: Cell): boolean =>
    cells.some((live) => samePosition(live, cell));

  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive([x + dx, y + dy])).length;

  const survives = (cell: Cell): boolean => {
    const neighborCount = countLiveNeighbors(cell);
    return neighborCount === 2 || neighborCount === 3;
  };

  const survivors = cells.filter(survives);

  const deadNeighbors: Cell[] = [];
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const candidate: Cell = [x + dx, y + dy];
      if (isAlive(candidate)) continue;
      if (deadNeighbors.some((c) => samePosition(c, candidate))) continue;
      deadNeighbors.push(candidate);
    }
  }

  const births = deadNeighbors.filter((cell) => countLiveNeighbors(cell) === 3);

  return [...survivors, ...births];
};

